def parse_python_file(file_path: str):
    """
    Parse a Python file and print all classes and functions.
    """

    with open(file_path, "r", encoding="utf-8") as f:
        source = f.read()

    tree = ast.parse(source)

    print(f"\n📄 File: {file_path}")
    print("=" * 60)

    for node in ast.walk(tree):

        if isinstance(node, ast.ClassDef):
            print(f"🏛️  Class: {node.name}")

        elif isinstance(node, ast.FunctionDef):
            print(f"⚙️  Function: {node.name}")

        elif isinstance(node, ast.AsyncFunctionDef):
            print(f"⚡ Async Function: {node.name}")

def extract_classes(file_path: str):
    """
    Extract all classes from a Python file.
    """

    with open(file_path, "r", encoding="utf-8") as f:
        source = f.read()

    tree = ast.parse(source)

    classes = []

    for node in ast.walk(tree):

        if isinstance(node, ast.ClassDef):

            bases = []

            for base in node.bases:

                if isinstance(base, ast.Name):
                    bases.append(base.id)

                elif isinstance(base, ast.Attribute):
                    bases.append(base.attr)

                else:
                    bases.append(ast.dump(base))

            methods = []

            for item in node.body:

                if isinstance(item, (ast.FunctionDef, ast.AsyncFunctionDef)):
                    methods.append(item.name)

            classes.append({
                "name": node.name,
                "file_path": file_path,
                "base_classes": bases,
                "methods": methods
            })

    return classes

def scan_python_files(repo_path: str):

    python_files = []

    for root, dirs, files in os.walk(repo_path):

        dirs[:] = [
            d for d in dirs
            if d not in IGNORE_FOLDERS
        ]

        for file in files:

            if file.endswith(".py"):

                full_path = os.path.join(root, file)

                python_files.append(full_path)

    return python_files

def extract_imports(file_path: str):
    """
    Extract all imports from a Python file and build an import map.
    """

    with open(file_path, "r", encoding="utf-8") as f:
        source = f.read()

    tree = ast.parse(source)

    imports = []
    import_map = {}

    for node in ast.walk(tree):

        # import module
        if isinstance(node, ast.Import):

            for alias in node.names:

                imports.append({
                    "module": alias.name,
                    "name": None,
                    "alias": alias.asname
                })

                local_name = alias.asname if alias.asname else alias.name
                import_map[local_name] = alias.name

        # from module import object
        elif isinstance(node, ast.ImportFrom):

            module = node.module

            for alias in node.names:

                imports.append({
                    "module": module,
                    "name": alias.name,
                    "alias": alias.asname
                })

                local_name = alias.asname if alias.asname else alias.name

                import_map[local_name] = f"{module}.{alias.name}"

    return {
        "file_path": file_path,
        "imports": imports,
        "import_map": import_map
    }
